1	// Copyright 2026 Scale Invariant, Inc.
2	// All rights reserved.
3	// SPDX-License-Identifier: LicenseRef-Proprietary
4	
5	//! Cipher Registry - Single source of truth for project prefixes
6	//!
7	//! A Cipher is a 2-5 character project prefix that owns exclusive namespace rights.
8	//! All kit artifacts must use prefixes derived from their cipher.
9	//!
10	//! Rules (from Prefix Naming Discipline):
11	//! - Lowercase letters only
12	//! - Globally unique
13	//! - Terminal exclusivity: a prefix either IS a name or HAS children, never both
14	//!
15	//! Declaration pattern: const values with compile-time uniqueness.
16	
17	/// Cipher represents a project's namespace root.
18	/// Uniqueness enforced at compile time by const declaration.
19	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
20	pub struct vofc_Cipher {
21	    prefix: &'static str,
22	    project: &'static str,
23	}
24	
25	impl vofc_Cipher {
26	    /// Create a new cipher at compile time.
27	    pub const fn new(prefix: &'static str, project: &'static str) -> Self {
28	        Self { prefix, project }
29	    }
30	
31	    /// Get the prefix string.
32	    pub const fn prefix(&self) -> &'static str {
33	        self.prefix
34	    }
35	
36	    /// Get the project name.
37	    pub const fn project(&self) -> &'static str {
38	        self.project
39	    }
40	
41	    /// Check if a string starts with this cipher's prefix.
42	    pub fn matches_prefix(&self, s: &str) -> bool {
43	        s.starts_with(self.prefix)
44	    }
45	
46	    /// Validate that a string follows cipher naming rules.
47	    /// Returns true if the string starts with this cipher's prefix
48	    /// and the character after the prefix (if any) is not part of
49	    /// another cipher's prefix (terminal exclusivity).
50	    pub fn validate_name(&self, name: &str) -> bool {
51	        if !name.starts_with(self.prefix) {
52	            return false;
53	        }
54	        // Name must have content after the prefix
55	        name.len() > self.prefix.len()
56	    }
57	
58	    /// Generate kit identifier by appending 'k' to prefix.
59	    /// Does not validate whether this cipher actually has a kit.
60	    pub fn kit_id(&self) -> String {
61	        format!("{}k", self.prefix)
62	    }
63	}
64	
65	// =============================================================================
66	// Project Cipher Registry
67	// =============================================================================
68	// Organized by domain. Each cipher owns exclusive namespace rights.
69	// Adding a new cipher here is a deliberate act requiring coordination.
70	
71	// -----------------------------------------------------------------------------
72	// Voce Viva Ecosystem (VO/VV)
73	// -----------------------------------------------------------------------------
74	
75	/// VV: Voce Viva - the universal kit present in every target repo
76	pub const VV: vofc_Cipher = vofc_Cipher::new("vv", "Voce Viva");
77	
78	/// VO: Vox Obscura - the kit forge infrastructure (never distributed)
79	pub const VO: vofc_Cipher = vofc_Cipher::new("vo", "Vox Obscura");
80	
81	// -----------------------------------------------------------------------------
82	// Portable Kits
83	// -----------------------------------------------------------------------------
84	
85	/// JJ: Job Jockey - project management and heat tracking
86	pub const JJ: vofc_Cipher = vofc_Cipher::new("jj", "Job Jockey");
87	
88	/// BU: Bash Utilities Kit - enterprise bash infrastructure
89	pub const BU: vofc_Cipher = vofc_Cipher::new("bu", "Bash Utilities");
90	
91	/// CM: Concept Model Kit - MCM/AXLA concept model tooling
92	pub const CM: vofc_Cipher = vofc_Cipher::new("cm", "Concept Model");
93	
94	/// HM: Hard-state Machine Kit - state machine infrastructure
95	pub const HM: vofc_Cipher = vofc_Cipher::new("hm", "Hard-state Machine");
96	
97	// -----------------------------------------------------------------------------
98	// Recipe Bottle Domain
99	// -----------------------------------------------------------------------------
100	
101	/// RB: Recipe Bottle - container orchestration and deployment
102	pub const RB: vofc_Cipher = vofc_Cipher::new("rb", "Recipe Bottle");
103	
104	/// CRG: Config Regime - configuration management
105	pub const CRG: vofc_Cipher = vofc_Cipher::new("crg", "Config Regime");
106	
107	// -----------------------------------------------------------------------------
108	// Tools and Utilities
109	// -----------------------------------------------------------------------------
110	
111	/// GAD: Google AsciiDoc Differ - diff visualization tool
112	pub const GAD: vofc_Cipher = vofc_Cipher::new("gad", "Google AsciiDoc Differ");
113	
114	/// CCC: Claude Code Container Kit - Docker/container operations
115	pub const CCC: vofc_Cipher = vofc_Cipher::new("ccc", "Claude Code Container");
116	
117	/// LMCI: Language Model Console Integration
118	pub const LMCI: vofc_Cipher = vofc_Cipher::new("lmci", "Language Model Console Integration");
119	
120	/// VSL: Visual SlickEdit Local Kit - IDE integration
121	pub const VSL: vofc_Cipher = vofc_Cipher::new("vsl", "Visual SlickEdit Local");
122	
123	// -----------------------------------------------------------------------------
124	// Concept Model Vocabulary
125	// -----------------------------------------------------------------------------
126	
127	/// MCM: Meta Concept Model - specification for concept models
128	pub const MCM: vofc_Cipher = vofc_Cipher::new("mcm", "Meta Concept Model");
129	
130	/// AXL: Axiom Lexicon - shared vocabulary definitions
131	pub const AXL: vofc_Cipher = vofc_Cipher::new("axl", "Axiom Lexicon");
132	
133	// -----------------------------------------------------------------------------
134	// Other Projects
135	// -----------------------------------------------------------------------------
136	
137	/// PB: Paneboard - cross-platform UI toolkit
138	pub const PB: vofc_Cipher = vofc_Cipher::new("pb", "Paneboard");
139	
140	/// WRS: Ward Realm Substrate - distributed state machine substrate
141	pub const WRS: vofc_Cipher = vofc_Cipher::new("wrs", "Ward Realm Substrate");
142	
143	/// SRF: Study Raft - learning and exploration
144	pub const SRF: vofc_Cipher = vofc_Cipher::new("srf", "Study Raft");
145	
146	// =============================================================================
147	// Registry Access
148	// =============================================================================
149	
150	/// All registered ciphers for iteration and validation.
151	pub const ALL_CIPHERS: &[vofc_Cipher] = &[
152	    // VO/VV ecosystem
153	    VV, VO,
154	    // Portable kits
155	    JJ, BU, CM, HM,
156	    // Recipe Bottle domain
157	    RB, CRG,
158	    // Tools and utilities
159	    GAD, CCC, LMCI, VSL,
160	    // Concept model vocabulary
161	    MCM, AXL,
162	    // Other projects
163	    PB, WRS, SRF,
164	];
165	
166	// =============================================================================
167	// Kit Registry
168	// =============================================================================
169	// Typed kit declarations for distribution. Field names align with VOS entity
170	// members (vosem_kit_id, vosem_display_name).
171	
172	/// A managed section declaration for CLAUDE.md.
173	/// Template content lives in vov_veiled/, copied to parcel during release.
174	#[derive(Debug, Clone, Copy)]
175	pub struct vofc_ManagedSection {
176	    /// Tag identifier for the section (e.g., "JJK", "BUK")
177	    pub tag: &'static str,
178	    /// Template file path relative to kit's vov_veiled/ directory
179	    pub template_path: &'static str,
180	}
181	
182	/// A distributable kit with typed cipher reference.
183	/// Kit identifier derived from cipher via cipher.kit_id().
184	#[derive(Debug, Clone, Copy)]
185	pub struct vofc_Kit {
186	    /// Reference to the kit's cipher (typed, not string).
187	    pub cipher: &'static vofc_Cipher,
188	    /// Human-readable name. See vosem_display_name.
189	    pub display_name: &'static str,
190	    /// Managed sections for CLAUDE.md. Templates in vov_veiled/.
191	    pub managed_sections: &'static [vofc_ManagedSection],
192	}
193	
194	/// Asset routing rule for kit installation.
195	/// Determines where files are copied during install.
196	#[derive(Debug, Clone, Copy)]
197	pub struct vofc_AssetRoute {
198	    /// Source pattern relative to kit directory.
199	    pub source_pattern: &'static str,
200	    /// Target path relative to target repo.
201	    pub target_path: &'static str,
202	    /// If true, routes to .claude/commands/ instead of target_path.
203	    pub is_command: bool,
204	}
205	
206	/// Kits included in VVK distribution.
207	/// Order matters: kits are installed in this order, affecting CLAUDE.md section ordering.
208	pub const DISTRIBUTABLE_KITS: &[vofc_Kit] = &[
209	    vofc_Kit {
210	        cipher: &BU,
211	        display_name: "Bash Utilities",
212	        managed_sections: &[
213	            vofc_ManagedSection { tag: "BUK", template_path: "vocbumc_core.md" },
214	        ],
215	    },
216	    vofc_Kit {
217	        cipher: &CM,
218	        display_name: "Concept Model",
219	        managed_sections: &[
220	            vofc_ManagedSection { tag: "CMK", template_path: "voccmmc_core.md" },
221	        ],
222	    },
223	    vofc_Kit {
224	        cipher: &JJ,
225	        display_name: "Job Jockey",
226	        managed_sections: &[
227	            vofc_ManagedSection { tag: "JJK", template_path: "vocjjmc_core.md" },
228	        ],
229	    },
230	    vofc_Kit {
231	        cipher: &VV,
232	        display_name: "Voce Viva",
233	        managed_sections: &[
234	            vofc_ManagedSection { tag: "VVK", template_path: "vocvvmc_core.md" },
235	        ],
236	    },
237	];
238	
239	/// Compatibility accessor: returns kit IDs as strings.
240	/// For callers that only need the kit identifier strings.
241	pub fn vofc_distributable_kit_ids() -> Vec<String> {
242	    DISTRIBUTABLE_KITS.iter().map(|k| k.cipher.kit_id()).collect()
243	}
244	
245	/// Find a kit by its ID (e.g., "jjk", "buk").
246	pub fn vofc_find_kit_by_id(kit_id: &str) -> Option<&'static vofc_Kit> {
247	    DISTRIBUTABLE_KITS.iter().find(|k| k.cipher.kit_id() == kit_id)
248	}
249	
250	// =============================================================================
251	// Claude Asset Signets
252	// =============================================================================
253	
254	/// Command signet suffix (appears after cipher prefix)
255	/// Pattern: {cipher}c-*.md
256	pub const VOFC_COMMAND_SIGNET_SUFFIX: &str = "c-";
257	
258	/// Hook signet suffix (appears after cipher prefix)
259	/// Pattern: {cipher}h-*.md
260	pub const VOFC_HOOK_SIGNET_SUFFIX: &str = "h-";
261	
262	/// Find a cipher by prefix.
263	pub fn vofc_find_by_prefix(prefix: &str) -> Option<&'static vofc_Cipher> {
264	    ALL_CIPHERS.iter().find(|c| c.prefix == prefix)
265	}
266	
267	/// Check if a prefix is registered.
268	pub fn vofc_is_registered(prefix: &str) -> bool {
269	    vofc_find_by_prefix(prefix).is_some()
270	}
271	
272	/// Validate terminal exclusivity: ensure no prefix is a prefix of another.
273	/// Returns None if valid, or Some pair of conflicting ciphers.
274	pub fn vofc_validate_terminal_exclusivity() -> Option<(&'static vofc_Cipher, &'static vofc_Cipher)> {
275	    for (i, a) in ALL_CIPHERS.iter().enumerate() {
276	        for b in ALL_CIPHERS.iter().skip(i + 1) {
277	            if a.prefix.starts_with(b.prefix) || b.prefix.starts_with(a.prefix) {
278	                return Some((a, b));
279	            }
280	        }
281	    }
282	    None
283	}
284	
