230	        let template_dest = templates_dir.join(section.template_path);
231	        fs::copy(&template_source, &template_dest)
232	            .map_err(|e| format!("Failed to copy template {}: {}", section.template_path, e))?;
233	
234	        count += 1;
235	    }
236	
237	    Ok(count)
238	}
239	
240	/// Collect a single kit's assets.
241	fn zvofr_collect_kit(
242	    source: &Path,
243	    staging: &Path,
244	    kit: &vofc_Kit,
245	) -> Result<(u32, u32), String> {
246	    let mut count = 0u32;
247	    let mut cmd_count = 0u32;
248	    let cipher = kit.cipher.prefix();
249	
250	    // Walk source directory
251	    let entries = zvofr_walk_dir(source)?;
252	
253	    for entry in entries {
254	        let rel_path = entry.strip_prefix(source)
255	            .map_err(|e| format!("Path strip failed: {}", e))?;
256	
257	        // Skip vov_veiled/ directory
258	        if zvofr_is_veiled_path(rel_path) {
259	            continue;
260	        }
261	
262	        // Determine destination
263	        let file_name = rel_path.file_name()
264	            .and_then(|n| n.to_str())
265	            .unwrap_or("");
266	
267	        let dest = if zvofr_is_command_file(file_name, cipher) {
268	            // Route commands to commands/ subdirectory
269	            cmd_count += 1;
270	            let commands_dir = staging.join("commands");
271	            fs::create_dir_all(&commands_dir)
272	                .map_err(|e| format!("Failed to create commands dir: {}", e))?;
273	            commands_dir.join(file_name)
274	        } else {
275	            // Default: preserve relative path
276	            staging.join(rel_path)
277	        };
278	
279	        // Create parent directories
280	        if let Some(parent) = dest.parent() {
281	            fs::create_dir_all(parent)
282	                .map_err(|e| format!("Failed to create dir {}: {}", parent.display(), e))?;
283	        }
284	
285	        // Copy file
286	        fs::copy(&entry, &dest)
287	            .map_err(|e| format!("Failed to copy {} to {}: {}", entry.display(), dest.display(), e))?;
288	
289	        count += 1;
290	    }
291	
292	    Ok((count, cmd_count))
293	}
294	
295	/// Collect Claude config assets for a single kit.
296	/// Scans .claude/commands/ and .claude/hooks/ at kit forge root for cipher-matched files.
297	/// Uses CWD as kit forge root (commands run from project root per launcher convention).
298	/// Returns (commands_collected, hooks_collected).
299	fn zvofr_collect_claude_assets(
300	    _kit_forge: &Path,
301	    staging: &Path,
302	    cipher: &str,
303	) -> Result<(u32, u32), String> {
304	    let mut commands_count = 0u32;
305	    let mut hooks_count = 0u32;
306	
307	    // Kit forge root is CWD (launcher cd's to project root before execution)
308	    let kit_forge_root = Path::new(".");
309	
310	    // Collect commands from .claude/commands/
311	    let commands_source = kit_forge_root.join(".claude").join("commands");
312	    if commands_source.exists() {
313	        let commands_dest = staging.join("claude").join("commands");
314	        fs::create_dir_all(&commands_dest)
315	            .map_err(|e| format!("Failed to create claude/commands dir: {}", e))?;
316	
317	        commands_count = zvofr_copy_matching_files(&commands_source, &commands_dest, cipher, true)?;
318	    }
319	
320	    // Collect hooks from .claude/hooks/
321	    let hooks_source = kit_forge_root.join(".claude").join("hooks");
322	    if hooks_source.exists() {
323	        let hooks_dest = staging.join("claude").join("hooks");
324	        fs::create_dir_all(&hooks_dest)
325	            .map_err(|e| format!("Failed to create claude/hooks dir: {}", e))?;
326	
327	        hooks_count = zvofr_copy_matching_files(&hooks_source, &hooks_dest, cipher, false)?;
328	    }
329	
330	    Ok((commands_count, hooks_count))
331	}
332	
333	/// Copy files matching cipher pattern from source to dest.
334	/// is_command determines whether to match commands (c-) or hooks (h-).
335	/// Returns count of files copied.
336	fn zvofr_copy_matching_files(
337	    source_dir: &Path,
338	    dest_dir: &Path,
339	    cipher: &str,
340	    is_command: bool,
341	) -> Result<u32, String> {
342	    let mut count = 0u32;
343	
344	    let entries = fs::read_dir(source_dir)
345	        .map_err(|e| format!("Failed to read directory {}: {}", source_dir.display(), e))?;
346	
347	    for entry in entries {
348	        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
349	        let path = entry.path();
350	
351	        if !path.is_file() {
352	            continue;
353	        }
354	
355	        let file_name = path
356	            .file_name()
357	            .and_then(|n| n.to_str())
358	            .unwrap_or("");
359	
360	        let matches = if is_command {
361	            zvofr_is_command_file(file_name, cipher)
362	        } else {
363	            zvofr_is_hook_file(file_name, cipher)
364	        };
365	
366	        if matches {
367	            let dest_path = dest_dir.join(file_name);
368	            fs::copy(&path, &dest_path)
369	                .map_err(|e| format!("Failed to copy {} to {}: {}", path.display(), dest_path.display(), e))?;
370	            count += 1;
371	        }
372	    }
373	
374	    Ok(count)
375	}
376	
377	/// Walk directory recursively, returning all file paths.
378	fn zvofr_walk_dir(dir: &Path) -> Result<Vec<PathBuf>, String> {
379	    let mut files = Vec::new();
380	
381	    if !dir.is_dir() {
382	        return Ok(files);
383	    }
384	
385	    let entries = fs::read_dir(dir)
386	        .map_err(|e| format!("Failed to read dir {}: {}", dir.display(), e))?;
387	
388	    for entry in entries {
389	        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
390	        let path = entry.path();
391	
392	        if path.is_dir() {
393	            files.extend(zvofr_walk_dir(&path)?);
394	        } else {
395	            files.push(path);
396	        }
397	    }
398	
399	    Ok(files)
400	}
401	
402	/// Check if path is within vov_veiled/ directory.
403	fn zvofr_is_veiled_path(rel_path: &Path) -> bool {
404	    for component in rel_path.components() {
405	        if let std::path::Component::Normal(name) = component {
406	            if name == "vov_veiled" {
407	                return true;
408	            }
409	        }
410	    }
411	    false
412	}
413	
414	/// Check if file is a command file (matches {cipher}c-*.md pattern).
415	fn zvofr_is_command_file(file_name: &str, cipher: &str) -> bool {
416	    let prefix = format!("{}{}", cipher, VOFC_COMMAND_SIGNET_SUFFIX);
417	    file_name.starts_with(&prefix) && file_name.ends_with(".md")
418	}
419	
420	/// Check if file is a hook file (matches {cipher}h-*.md pattern).
421	fn zvofr_is_hook_file(file_name: &str, cipher: &str) -> bool {
422	    let prefix = format!("{}{}", cipher, VOFC_HOOK_SIGNET_SUFFIX);
423	    file_name.starts_with(&prefix) && file_name.ends_with(".md")
424	}
425	
426	/// Compute order-independent super-SHA of staging directory.
427	fn zvofr_compute_super_sha(staging_dir: &Path) -> Result<String, String> {
428	    use std::collections::BTreeSet;
429	
430	    let mut file_hashes: BTreeSet<String> = BTreeSet::new();
431	
432	    let files = zvofr_walk_dir(staging_dir)?;
433	
434	    for file_path in files {
435	        let rel_path = file_path.strip_prefix(staging_dir)
436	            .map_err(|e| format!("Strip prefix failed: {}", e))?;
437	
438	        // Skip brand file itself
439	        if rel_path == Path::new("vvbf_brand.json") {
440	            continue;
441	        }
442	
443	        // Hash: path + content
444	        let path_str = rel_path.to_string_lossy();
445	        let content = fs::read(&file_path)
446	            .map_err(|e| format!("Failed to read {}: {}", file_path.display(), e))?;
447	
448	        let hash = zvofr_sha256_bytes(format!("{}:{}", path_str, zvofr_sha256_bytes(&content)).as_bytes());
449	        file_hashes.insert(hash);
450	    }
451	
452	    // Combine all hashes
453	    let combined = file_hashes.into_iter().collect::<Vec<_>>().join("\n");
454	    Ok(zvofr_sha256_bytes(combined.as_bytes()))
455	}
456	
457	/// Compute SHA256 of bytes, return hex string.
458	fn zvofr_sha256_bytes(data: &[u8]) -> String {
459	    // Simple SHA256 implementation using standard library
460	    // In production, would use sha2 crate, but avoiding extra dependencies
461	    use std::process::{Command, Stdio};
462	    use std::io::Write;
463	
464	    let mut child = Command::new("shasum")
465	        .args(["-a", "256"])
466	        .stdin(Stdio::piped())
467	        .stdout(Stdio::piped())
468	        .spawn()
469	        .expect("Failed to spawn shasum");
470	
471	    {
472	        let stdin = child.stdin.as_mut().expect("Failed to open stdin");
473	        stdin.write_all(data).expect("Failed to write to stdin");
474	    }
475	
476	    let output = child.wait_with_output().expect("Failed to read shasum output");
477	    let stdout = String::from_utf8_lossy(&output.stdout);
478	    stdout.split_whitespace().next().unwrap_or("").to_string()
479	}
480	
481	/// Load registry from JSON file.
482	fn zvofr_load_registry(path: &Path) -> Result<BTreeMap<u32, vofr_RegistryEntry>, String> {
483	    if !path.exists() {
484	        return Ok(BTreeMap::new());
485	    }
486	
487	    let content = fs::read_to_string(path)
488	        .map_err(|e| format!("Failed to read registry: {}", e))?;
489	
490	    let json: serde_json::Value = serde_json::from_str(&content)
491	        .map_err(|e| format!("Failed to parse registry JSON: {}", e))?;
492	
493	    let brands = json.get(VOFR_REGISTRY_BRANDS)
494	        .and_then(|v| v.as_object())
495	        .ok_or_else(|| "Registry missing 'vovr_brands' object".to_string())?;
496	
497	    let mut registry = BTreeMap::new();
498	
499	    for (key, value) in brands {
500	        let brand: u32 = key.parse()
501	            .map_err(|e| format!("Invalid brand key '{}': {}", key, e))?;
502	
503	        let date = value.get("date")
504	            .and_then(|v| v.as_str())
505	            .ok_or_else(|| format!("Brand {} missing 'date'", brand))?
506	            .to_string();
507	
508	        let sha = value.get("sha")
509	            .and_then(|v| v.as_str())
510	            .ok_or_else(|| format!("Brand {} missing 'sha'", brand))?
511	            .to_string();
512	
513	        registry.insert(brand, vofr_RegistryEntry { date, sha });
514	    }
515	
516	    Ok(registry)
517	}
518	
519	/// Save registry to JSON file.
520	fn zvofr_save_registry(path: &Path, registry: &BTreeMap<u32, vofr_RegistryEntry>) -> Result<(), String> {
521	    let mut brands = serde_json::Map::new();
522	
523	    for (brand, entry) in registry {
524	        let mut entry_obj = serde_json::Map::new();
525	        entry_obj.insert("date".to_string(), serde_json::Value::String(entry.date.clone()));
526	        entry_obj.insert("sha".to_string(), serde_json::Value::String(entry.sha.clone()));
527	        brands.insert(brand.to_string(), serde_json::Value::Object(entry_obj));
528	    }
529	
530	    let mut root = serde_json::Map::new();
531	    root.insert(VOFR_REGISTRY_BRANDS.to_string(), serde_json::Value::Object(brands));
532	
533	    let json = serde_json::to_string_pretty(&serde_json::Value::Object(root))
534	        .map_err(|e| format!("Failed to serialize registry: {}", e))?;
535	
536	    fs::write(path, json)
537	        .map_err(|e| format!("Failed to write registry: {}", e))?;
538	
539	    Ok(())
540	}
541	
542	/// Find brand by SHA.
543	fn zvofr_find_by_sha(registry: &BTreeMap<u32, vofr_RegistryEntry>, sha: &str) -> Option<u32> {
544	    for (brand, entry) in registry {
545	        if entry.sha == sha {
546	            return Some(*brand);
547	        }
548	    }
549	    None
550	}
551	
552	/// Allocate next sequential brand.
553	fn zvofr_allocate_brand(registry: &BTreeMap<u32, vofr_RegistryEntry>) -> u32 {
554	    registry.keys().max().map(|m| m + 1).unwrap_or(VOFR_BRAND_START)
555	}
556	
557	/// Generate date string in YYMMDD-HHMM format.
558	fn zvofr_generate_date() -> String {
559	    use std::process::Command;
560	
561	    let output = Command::new("date")
562	        .args(["+%y%m%d-%H%M"])
563	        .output()
564	        .expect("Failed to run date command");
565	
566	    String::from_utf8_lossy(&output.stdout).trim().to_string()
567	}
568	
569	/// Write brand file to staging.
570	fn zvofr_write_brand_file(
571	    path: &Path,
572	    brand: u32,
573	    date: &str,
574	    sha: &str,
575	    commit: &str,
576	    kits: &[String],
577	) -> Result<(), String> {
578	    let mut root = serde_json::Map::new();
579	
580	    root.insert(VOFR_BRAND_BRAND.to_string(), serde_json::Value::Number(brand.into()));
581	    root.insert(VOFR_BRAND_DATE.to_string(), serde_json::Value::String(date.to_string()));
582	    root.insert(VOFR_BRAND_SHA.to_string(), serde_json::Value::String(sha.to_string()));
583	    root.insert(VOFR_BRAND_COMMIT.to_string(), serde_json::Value::String(commit.to_string()));
584	
585	    let kit_values: Vec<serde_json::Value> = kits
586	        .iter()
587	        .map(|k| serde_json::Value::String(k.clone()))
588	        .collect();
589	    root.insert(VOFR_BRAND_KITS.to_string(), serde_json::Value::Array(kit_values));
590	
591	    let json = serde_json::to_string_pretty(&serde_json::Value::Object(root))
592	        .map_err(|e| format!("Failed to serialize brand file: {}", e))?;
593	
594	    fs::write(path, json)
595	        .map_err(|e| format!("Failed to write brand file: {}", e))?;
596	
597	    Ok(())
598	}
599	
600	#[cfg(test)]
601	mod tests {
602	    use super::*;
603	
604	    #[test]
605	    fn vofr_is_command_file_test() {
606	        assert!(zvofr_is_command_file("jjc-heat-mount.md", "jj"));
607	        assert!(zvofr_is_command_file("vvc-commit.md", "vv"));
608	        assert!(!zvofr_is_command_file("jju_utility.sh", "jj"));
609	        assert!(!zvofr_is_command_file("README.md", "jj"));
610	        assert!(!zvofr_is_command_file("jjc-heat-mount.txt", "jj"));
611	    }
612	
613	    #[test]
614	    fn vofr_is_veiled_path_test() {
615	        assert!(zvofr_is_veiled_path(Path::new("vov_veiled/test.rs")));
616	        assert!(zvofr_is_veiled_path(Path::new("foo/vov_veiled/bar.rs")));
617	        assert!(!zvofr_is_veiled_path(Path::new("commands/jjc-test.md")));
618	        assert!(!zvofr_is_veiled_path(Path::new("buc_command.sh")));
619	    }
620	
621	    #[test]
622	    fn vofr_brand_allocation_test() {
623	        let empty: BTreeMap<u32, vofr_RegistryEntry> = BTreeMap::new();
624	        assert_eq!(zvofr_allocate_brand(&empty), VOFR_BRAND_START);
625	
626	        let mut registry = BTreeMap::new();
627	        registry.insert(1000, vofr_RegistryEntry {
628	            date: "260117-1400".to_string(),
629	            sha: "abc123".to_string(),
630	        });
631	        assert_eq!(zvofr_allocate_brand(&registry), 1001);
632	
633	        registry.insert(1005, vofr_RegistryEntry {
634	            date: "260117-1500".to_string(),
635	            sha: "def456".to_string(),
636	        });
637	        assert_eq!(zvofr_allocate_brand(&registry), 1006);
638	    }
639	}
