621	/// Returns (files_copied, commands_routed, hooks_routed).
622	fn zvofe_copy_kit(
623	    source: &Path,
624	    dest: &Path,
625	    project_root: &Path,
626	    kit_id: &str,
627	) -> Result<(u32, u32, u32), String> {
628	    let mut files = 0u32;
629	    let mut commands = 0u32;
630	    let mut hooks = 0u32;
631	
632	    // Get cipher from kit_id (e.g., "jjk" -> "jj")
633	    let cipher = &kit_id[..kit_id.len().saturating_sub(1)];
634	
635	    // Walk source directory
636	    let entries = zvofe_walk_dir(source)?;
637	
638	    for entry in entries {
639	        let rel_path = entry
640	            .strip_prefix(source)
641	            .map_err(|e| format!("Path strip failed: {}", e))?;
642	
643	        let file_name = rel_path
644	            .file_name()
645	            .and_then(|n| n.to_str())
646	            .unwrap_or("");
647	
648	        // Determine destination based on file type
649	        let dest_path = if zvofe_is_command_file(file_name, cipher) {
650	            // Route commands to .claude/commands/
651	            let commands_dir = project_root.join(".claude").join("commands");
652	            fs::create_dir_all(&commands_dir)
653	                .map_err(|e| format!("Failed to create commands dir: {}", e))?;
654	            commands += 1;
655	            commands_dir.join(file_name)
656	        } else if zvofe_is_hook_file(file_name, cipher) {
657	            // Route hooks to .claude/hooks/
658	            let hooks_dir = project_root.join(".claude").join("hooks");
659	            fs::create_dir_all(&hooks_dir)
660	                .map_err(|e| format!("Failed to create hooks dir: {}", e))?;
661	            hooks += 1;
662	            hooks_dir.join(file_name)
663	        } else {
664	            // Default: preserve relative path in kit directory
665	            dest.join(rel_path)
666	        };
667	
668	        // Create parent directories
669	        if let Some(parent) = dest_path.parent() {
670	            fs::create_dir_all(parent)
671	                .map_err(|e| format!("Failed to create dir {}: {}", parent.display(), e))?;
672	        }
673	
674	        // Copy file
675	        fs::copy(&entry, &dest_path)
676	            .map_err(|e| format!("Failed to copy {} to {}: {}", entry.display(), dest_path.display(), e))?;
677	
678	        files += 1;
679	    }
680	
681	    Ok((files, commands, hooks))
682	}
